export const DATA_DUMMY = (name, length = 15) => {
  let data: any[] = [];
  for (let i = 0; i < length; i++) {
    const element = {
      id: i + 1,
      title: `${name} ${i} Title`,
      status: i % 2 == 0 ? 'active' : 'disable',
      desc: `${name} ${i} Desc`,
      createdAt: `2026-0${i}-0${i}T0${i}:00:00Z`,
      updatedAt: `2026-0${i+1}-0${i+1}T0${i+1}:00:00Z`,
      // actions: '1',
    }
    data.push(element)
  }
  return data
}
